using Microsoft.Extensions.AI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

IChatClient innerClient = new OpenAI.Chat.ChatClient(
    model: "gpt-4o-mini-2024-07-18",
    apiKey: apiKey).AsIChatClient();

IChatClient client = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research agent. Your job is to thoroughly research a given topic
        using web searches and organize your findings in notes.

        Follow this workflow:
        1. Search the web with 2-3 different queries to cover the topic broadly
        2. For each search, review the results and save key findings as notes
        3. After gathering enough information, retrieve all notes to review them
        4. Provide a comprehensive, well-structured summary of your research

        Guidelines:
        - Use varied search queries to get diverse perspectives
        - Save specific facts, statistics, and key points as notes
        - Always cite sources (URLs) in your notes and final summary
        - Be thorough but concise in your final summary
        """),
    new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}"),
];

var options = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
    Tools = [.. tools],
};

Console.WriteLine("Agent is working...\n");

ChatResponse response = await client.GetResponseAsync(messages, options);

Console.WriteLine("=== Research Summary ===\n");
Console.WriteLine(response.Text ?? "No summary generated.");
Console.WriteLine($"\nNotes collected: {notebook.Count}");

