using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability by querying DuckDuckGo and parsing HTML results.
/// </summary>
public static partial class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    [Description("Search the web for information on a topic. Returns the top results with titles, URLs, and snippets.")]
    public static async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await s_httpClient.GetStringAsync(url);

            var results = ParseResults(html);
            if (results.Count == 0)
                return $"No results found for: {query}";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"\n");

            int limit = Math.Min(results.Count, 5);
            for (int i = 0; i < limit; i++)
            {
                var (title, link, snippet) = results[i];
                sb.AppendLine($"{i + 1}. {title}");
                sb.AppendLine($"   URL: {link}");
                sb.AppendLine($"   {snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<(string Title, string Url, string Snippet)> ParseResults(string html)
    {
        var results = new List<(string, string, string)>();

        var links = ResultLinkRegex().Matches(html);
        var snippets = ResultSnippetRegex().Matches(html);

        int count = Math.Min(links.Count, snippets.Count);
        for (int i = 0; i < count; i++)
        {
            var title = StripHtml(links[i].Groups[2].Value);
            var url = ExtractUrl(links[i].Groups[1].Value);
            var snippet = StripHtml(snippets[i].Groups[1].Value);

            if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(url))
                results.Add((title, url, snippet));
        }

        return results;
    }

    private static string ExtractUrl(string rawHref)
    {
        var decoded = WebUtility.HtmlDecode(rawHref);

        // DuckDuckGo wraps URLs in a redirect; extract the actual target
        var match = UddgParamRegex().Match(decoded);
        if (match.Success)
            return WebUtility.UrlDecode(match.Groups[1].Value);

        return decoded;
    }

    private static string StripHtml(string input) =>
        HtmlTagRegex().Replace(WebUtility.HtmlDecode(input), "").Trim();

    [GeneratedRegex("""<a[^>]*class="result__a"[^>]*href="([^"]*?)"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultLinkRegex();

    [GeneratedRegex("""<a[^>]*class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultSnippetRegex();

    [GeneratedRegex("""uddg=([^&]+)""")]
    private static partial Regex UddgParamRegex();

    [GeneratedRegex("""<[^>]+>""")]
    private static partial Regex HtmlTagRegex();
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// In-memory notebook that stores research findings as titled notes.
/// </summary>
public sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Save a research finding as a note. Use this to record key facts, statistics, or insights discovered during research.")]
    public string AddNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The note content — key findings, facts, or quotes with source URLs")] string content)
    {
        _notes.Add((title, content));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all research notes collected so far. Call this before writing your final summary to review all findings.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        sb.AppendLine();

        for (int i = 0; i < _notes.Count; i++)
        {
            var (title, content) = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {title} ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

